class StockPrice {
    private final Map<Integer, Integer> tsToPrice = new HashMap<>();
    private final TreeMap<Integer, Integer> freq = new TreeMap<>();
    private int latestTs = 0;

    public StockPrice() {}

    public void update(int timestamp, int price) {
        if (tsToPrice.containsKey(timestamp)) {
            int oldPrice = tsToPrice.get(timestamp);
            int cnt = freq.get(oldPrice);
            if (cnt == 1) freq.remove(oldPrice);
            else freq.put(oldPrice, cnt - 1);
        }
        tsToPrice.put(timestamp, price);
        freq.put(price, freq.getOrDefault(price, 0) + 1);
        if (timestamp >= latestTs) latestTs = timestamp;
    }

    public int current() {
        return tsToPrice.get(latestTs);
    }

    public int maximum() {
        return freq.lastKey();
    }

    public int minimum() {
        return freq.firstKey();
    }
}
```
